import React, { useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();

  // Function to handle smooth scrolling
  const scrollToSection = (id) => {
    const section = document.getElementById(id);
    if (section) {
      window.scrollTo({
        top: section.offsetTop - 80, // Adjust offset if needed
        behavior: 'smooth'
      });
    }
  };

  useEffect(() => {
    if (location.pathname !== '/') return;

    const onScroll = () => {
      let scrollPosition = window.scrollY;
      const links = document.querySelectorAll('.navmenu a');

      links.forEach(link => {
        const sectionId = link.getAttribute('data-section');
        if (!sectionId) return;

        let section = document.getElementById(sectionId);

        if (section) {
          let sectionTop = section.offsetTop - 100;
          let sectionBottom = sectionTop + section.offsetHeight;

          if (scrollPosition >= sectionTop && scrollPosition < sectionBottom) {
            links.forEach(nav => nav.classList.remove('active'));
            link.classList.add('active');
          }
        }
      });
    };

    window.addEventListener('scroll', onScroll);
    onScroll();

    return () => {
      window.removeEventListener('scroll', onScroll);
    };
  }, [location.pathname]);

  return (
    <header id="header" className="header d-flex flex-column justify-content-center">
      <i className="header-toggle d-xl-none bi bi-list"></i>
      <nav id="navmenu" className="navmenu">
        <ul>
          {location.pathname === "/" ? (
            <>
              <li><button onClick={() => scrollToSection('hero')} className="active"><i className="bi bi-house navicon"></i><span>Home</span></button></li>
              <li><button onClick={() => scrollToSection('about')}><i className="bi bi-person navicon"></i><span>About</span></button></li>
              <li><button onClick={() => scrollToSection('skills')}><i className="bi bi-lightbulb navicon"></i><span>Skills</span></button></li>
              <li><button onClick={() => scrollToSection('resume')}><i className="bi bi-file-earmark-text navicon"></i><span>Resume</span></button></li>
              <li><button onClick={() => scrollToSection('platforms')}><i className="bi bi-hdd-stack navicon"></i><span>Platform</span></button></li>
              <li><button onClick={() => scrollToSection('contact')}><i className="bi bi-envelope navicon"></i><span>Contact</span></button></li>
            </>
          ) : (
            <li>
              <Link to="/" className="active">
                <i className="bi bi-arrow-left navicon"></i><span>Home</span>
              </Link>
            </li>
          )}
        </ul>
      </nav>
    </header>
  );
};

export default Navbar;
